export default {"backend":"DomBackend","source":"// neocalendar — the Laszlo Calendar rewritten from the ground up in Declare.\n// The contract is SPEC.md (extracted from the running original + its source\n// read for intent); this file implements the spec, not the original's\n// structure. Stage 3: the three view modes (month / week / day) + the open\n// day, with the 500ms slider motion; mode-aware navigation (SPEC §12 B–D).\n// Grid geometry is exact; chrome is drawn (no images except the logo/menubar\n// holdouts) — \"geometry exact, chrome or better\".\n\nfont Cal [ family = \"Verdana\" ]\n\n\n// ── colors (SPEC §3–4; sampled + source-verified) ────────────────────────────\n// Day-cell bodies: weekday #9BA9B1 · weekend #879BA8 · out-of-month #768A97 ·\n// selected/hilite #D3D3D3. Event categories: default/holiday/astro/milestone.\n\n\n// ── EventBar — one event in a day's closed list (SPEC §4) ───────────────────\n// A 22px bar: category fill, 1px white top hairline + #555 bottom (drawn),\n// short time (\"9a\") then title. The open/timeline form arrives in Stage 4.\n\nclass EventBar extends View [\n    width = { parent.width }, height = 22,\n    clip = true,\n\n    category: string = \"\",\n    selected: boolean = false,\n    dayKey: string = \"\",\n\n    // Selected: the bar goes near-white with a category-tinted grip texture and\n    // an ⓘ button (SPEC §5 selector chrome); a click selects day + event (§6).\n    fill = { this.selected ? 0xFAFAFA\n           : this.category == \"holiday\"   ? 0xCBD1C5\n           : this.category == \"astro\"     ? 0xC5C3D5\n           : this.category == \"milestone\" ? 0xBBC6D1\n           :                           0xC6CEDC },\n\n    draw(d) {\n        d.fillStyle = 0xFFFFFF\n        d.fillRect(0, 0, this.width, 1)\n        d.fillStyle = 0x555555\n        d.fillRect(0, this.height - 1, this.width, 1)\n        if (this.selected) {\n            d.fillStyle = 0x8A98A0\n            for (let gx = 3; gx < this.width - 3; gx += 4) {\n                d.fillRect(gx, 2, 1, 2); d.fillRect(gx, this.height - 4, 1, 2)\n                }\n            }\n        },\n\n    info:  InfoButton [ x = 2, y = 4, visible = { classroot.selected } ],\n    time:  Text [ x = { classroot.selected ? 19 : 4 }, y = 6, fontSize = 10,\n                  textColor = #4B5D6C, text = :timeLabel ],\n    title: Text [ x = { parent.time.x + parent.time.width + 5 }, y = 6,\n                  width = { parent.width - this.x - 2 }, fontSize = 10,\n                  textColor = #4B5D6C, text = :title ],\n\n    onMouseDown() { this.root.startDrag(:id) },\n    onMouseMove(e) { this.root.dragMove(e.x, e.y) },\n    onMouseUp()   { this.root.endDrag() },\n    onClick() { if (!this.root.dragOccurred) this.root.selectEvent(:id, this.dayKey) },\n    ]\n\n\n// ── InfoButton — the ⓘ on a selected event (opens the info panel, §5/§7) ─────\n// A drawn 14px disc with an italic-ish \"i\"; inherits the event cursor so its\n// click knows which event (:id) to open.\n\nclass InfoButton extends View [\n    width = 14, height = 14, cornerRadius = 7,\n    fill = gradient(stop(0, 0xF4F4F4), stop(1, 0xAEB6BD)),\n    stroke = stroke(1, #7C8A92),\n\n    glyph: Text [ x = 5, y = 2, fontSize = 9, fontWeight = bold,\n                  textColor = #4B5D6C, text = \"i\" ],\n\n    onClick() { this.root.showInfo(:id) },\n    ]\n\n\n// ── PlusMinus — the corner open/close button of the selected-day chrome (§5) ──\n// `+` opens the selected day in place; `−` (when already open) collapses it /\n// returns to the month. A drawn glyph — the original used button bitmaps.\n\nclass PlusMinus extends View [\n    isOpen: boolean = false,\n    width = 11, height = 11, cornerRadius = 2,\n    fill = gradient(stop(0, 0xE8ECEC), stop(0.5, 0xC2CBCE), stop(1, 0x8A9BA3)),\n    stroke = stroke(1, #46606C),\n\n    draw(d) {\n        d.fillStyle = 0x2E4550\n        d.fillRect(2, 5, 7, 1)               // the bar — both `+` and `−`\n        if (!this.isOpen) d.fillRect(5, 2, 1, 7)  // the stem — `+` only\n        },\n\n    onClick() {\n        if (this.isOpen) this.root.closeDay()\n        else this.root.openDay(this.root.selectedKey)\n        },\n    ]\n\n\n// ── Stepper — a value with ‹ › nudges (the info panel's date/time rows, §7) ──\n// `field` picks the action (date = ±1 day; start = ±15m move; end = ±15m\n// duration); `label` is the formatted value, bound at the instance site.\n\nclass Stepper extends View [\n    field: string = \"\",\n    label: string = \"\",\n    width = 120, height = 16,\n    fill = #FFFFFF,\n    stroke = stroke(1, #A8ACA6),\n\n    val: Text [ x = 5, y = 2, fontSize = 10, textColor = #2E3E48, text = { classroot.label } ],\n\n    left: View [ x = { parent.width - 28 }, y = 1, width = 13, height = 14, cornerRadius = 2,\n        fill = gradient(stop(0, 0xE6EAEA), stop(1, 0x99A5AD)),\n        draw(d) { d.fillStyle = 0x33454F\n                  d.beginPath(); d.moveTo(8, 3); d.lineTo(4, 7); d.lineTo(8, 11); d.fill() },\n        onClick() { this.root.stepField(classroot.field, -1) } ],\n    right: View [ x = { parent.width - 14 }, y = 1, width = 13, height = 14, cornerRadius = 2,\n        fill = gradient(stop(0, 0xE6EAEA), stop(1, 0x99A5AD)),\n        draw(d) { d.fillStyle = 0x33454F\n                  d.beginPath(); d.moveTo(5, 3); d.lineTo(9, 7); d.lineTo(5, 11); d.fill() },\n        onClick() { this.root.stepField(classroot.field, 1) } ],\n    ]\n\n\n// ── AccordionSection — one collapsible panel tab (Notes/Location/Attendees) ──\n// One open at a time (App.openTab); the open section's multiline field fills the\n// area and pushes the sections below it down (SPEC §7). Header bevel hairlines\n// + a disclosure triangle, drawn.\n\nclass AccordionSection extends View [\n    idx: number = 0,\n    label: string = \"\",\n    width = 197,\n    y = { 90 + this.idx * 20 + (this.idx > this.root.openTab ? 330 : 0) },\n\n    hdr: View [ width = { parent.width }, height = 20,\n        fill = { this.root.openTab == classroot.idx ? 0xE2E4DF : 0xEEF0EB },\n        draw(d) {\n            d.fillStyle = 0xFDFFFF; d.fillRect(0, 0, this.width, 1)\n            d.fillStyle = 0xC6C7C4; d.fillRect(0, this.height - 1, this.width, 1)\n            d.fillStyle = 0x5A6A72\n            d.beginPath()\n            if (this.root.openTab == classroot.idx) {\n                d.moveTo(this.width - 14, 7); d.lineTo(this.width - 6, 7); d.lineTo(this.width - 10, 13)\n                }\n            else { d.moveTo(this.width - 12, 6); d.lineTo(this.width - 6, 9.5); d.lineTo(this.width - 12, 13) }\n            d.fill()\n            },\n        lbl: Text [ x = 6, y = 5, fontSize = 10, textColor = #3A4A50, text = { classroot.label } ],\n        onClick() { this.root.setTab(classroot.idx) } ],\n\n    area: TextInput [ x = 2, y = 20, width = { parent.width - 4 }, height = 326,\n        multiline = true, fill = #FFFFFF, fontSize = 10, textColor = #333333,\n        visible = { this.root.openTab == classroot.idx } ],\n    ]\n\n\n// ── HourLabel — one hour marker down the open-timeline's left gutter (SPEC §3)\n// Replicated over the store's `hours` records ({ num, ampm, y, bold }); the\n// number is 10px (bold on 12a/12p), the am/pm a 7px subscript. Centered on the\n// hour rule at :y.\n\nclass HourLabel extends View [\n    num:  Text [ x = 2, fontSize = 10, textColor = #4B5D6C,\n                 fontWeight = { :bold ? \"bold\" : \"normal\" }, text = :num ],\n    ampm: Text [ x = { parent.num.x + parent.num.width }, y = 3, fontSize = 7,\n                 textColor = #4B5D6C, text = :ampm ],\n    ]\n\n\n// ── TimeEvent — an event in the open hour-timeline (SPEC §3–4) ───────────────\n// Positioned/sized by time: y = start·(22/60)+11, height = max(22, dur·22/60).\n// Category fill, a category-tinted time gutter (29px, 30% opacity) at the left,\n// title only (the closed form's leading time is redundant on a timeline).\n\nclass TimeEvent extends View [\n    category: string = \"\",\n    clip = true,\n    selected: boolean = false,\n    dayKey: string = \"\",\n\n    fill = { this.selected ? 0xFAFAFA\n           : this.category == \"holiday\"   ? 0xCBD1C5\n           : this.category == \"astro\"     ? 0xC5C3D5\n           : this.category == \"milestone\" ? 0xBBC6D1\n           :                           0xC6CEDC },\n\n    // Placed by time; overlapping events share the width by lane (§12-E — the\n    // store hands each event its lane index and the cluster's lane count).\n    y = { :start * 22 / 60 + 11 },\n    height = { Math.max(22, (:end - :start) * 22 / 60) },\n    x = { :lane * (parent.width / :lanes) },\n    width = { parent.width / :lanes },\n\n    draw(d) {\n        if (!this.selected) {\n            d.fillStyle = this.category == \"holiday\"   ? \"rgba(88,116,87,0.30)\"\n                        : this.category == \"astro\"     ? \"rgba(76,94,126,0.30)\"\n                        : this.category == \"milestone\" ? \"rgba(76,94,126,0.30)\"\n                        :                           \"rgba(93,132,203,0.30)\"\n            d.fillRect(0, 1, 29, this.height - 2)\n            }\n        d.fillStyle = 0xFFFFFF\n        d.fillRect(0, 0, this.width, 1)\n        d.fillStyle = 0x555555\n        d.fillRect(0, this.height - 1, this.width, 1)\n        if (this.selected) {\n            d.fillStyle = 0x8A98A0\n            for (let gx = 3; gx < this.width - 3; gx += 4) {\n                d.fillRect(gx, 2, 1, 2); d.fillRect(gx, this.height - 4, 1, 2)\n                }\n            }\n        },\n\n    info:  InfoButton [ x = 2, y = 4, visible = { classroot.selected } ],\n    time:  Text [ x = 19, y = 4, fontSize = 10, textColor = #4B5D6C,\n                  visible = { classroot.selected }, text = :timeLabel ],\n    title: Text [ x = { classroot.selected ? 36 : 10 }, y = 4, fontSize = 10,\n                  textColor = #4B5D6C, width = { parent.width - this.x - 2 }, text = :title ],\n\n    onMouseDown() { this.root.startDrag(:id) },\n    onMouseMove(e) { this.root.dragMove(e.x, e.y) },\n    onMouseUp()   { this.root.endDrag() },\n    onClick() { if (!this.root.dragOccurred) this.root.selectEvent(:id, this.dayKey) },\n    ]\n\n\n// ── DayCell — one day of the grid (SPEC §3) ─────────────────────────────────\n// Closed form: a drawn frame — day number on the dark strip, body colored by\n// kind, events stacked in start order (the store pre-sorts, so a plain vertical\n// stack IS the sorted list). OPEN form (in place in month, widened column in\n// week, the day view): the closed list gives way to an hour TIMELINE — the\n// `opened` state on the body swaps them, so only open cells build a timeline.\n// Geometry (x/y/width/height/visible) is owned by the grid's CalendarGrid\n// layout, not the cell.\n\nclass DayCell extends View [\n    dayKey: string = \"\",\n    selected: boolean = false,\n    open: boolean = false,\n\n    // The frame, drawn: a 1px #7A949E ring around the #526C7B strip, with the\n    // original's rounded TOP-LEFT corner (r≈5.5 — the `ctl` art; the other\n    // three corners are square, so cornerRadius can't express it).\n    draw(d) {\n        // Selected: the ring lightens to a bevel — the floating selected-day\n        // chrome (SPEC §5); its corner +/- button rides at the top-right.\n        d.fillStyle = this.selected ? 0xCAD5DA : 0x7A949E\n        d.beginPath()\n        d.moveTo(5.5, 0); d.lineTo(this.width, 0); d.lineTo(this.width, this.height)\n        d.lineTo(0, this.height); d.lineTo(0, 5.5)\n        d.arc(5.5, 5.5, 5.5, Math.PI, 1.5 * Math.PI, false)\n        d.fill()\n        d.fillStyle = 0x526C7B\n        d.beginPath()\n        d.moveTo(5.5, 1); d.lineTo(this.width - 1, 1); d.lineTo(this.width - 1, this.height - 1)\n        d.lineTo(1, this.height - 1); d.lineTo(1, 5.5)\n        d.arc(5.5, 5.5, 4.5, Math.PI, 1.5 * Math.PI, false)\n        d.fill()\n        },\n\n    // Geometry (x/y/width/height/visible) is owned by the grid's CalendarGrid\n    // layout — the cell carries none of the slide machinery any more: the\n    // layout glides every cell through one `t`, and the reveal-at-end rule is a\n    // function of t inside the layout, not a per-cell timer here.\n\n    num: Text [ x = 4, y = 4, fontSize = 10,\n        text = { \"\" + :num },\n        textColor = { :inMonth ? 0xDAE3E8 : 0x7E929F } ],\n\n    // The selected-day chrome's corner button: `+` to open, `−` to close.\n    pm: PlusMinus [ x = { parent.width - 14 }, y = 3,\n        visible = { classroot.selected }, isOpen = { classroot.open } ],\n\n    body: View [ x = 3, y = 19, width = { parent.width - 8 }, height = { parent.height - 26 },\n        clip = true,\n        fill = { classroot.selected || this.root.dragOverKey == classroot.dayKey ? 0xD3D3D3\n               : :inMonth ? (:weekend ? 0x879BA8 : 0x9BA9B1) : 0x768A97 },\n\n        // Closed form: the sorted event list (hidden the moment the cell opens).\n        list: View [ width = { parent.width }, visible = { !classroot.open },\n            layout: SimpleLayout [ axis = y ],\n            EventBar [ datapath = :events[], category = :category,\n                dayKey = { classroot.dayKey }, selected = { this.root.selectedEvent == :id } ],\n            ],\n\n        // Open form: an hour timeline, built only while the cell is open. The\n        // hour rules are drawn (22px/hour, +11px half-hour zero); labels ride\n        // the store's `hours` records down a 28px gutter; events sit by time.\n        opened: State [ applied = { classroot.open },\n            // The scrolling content (611px = 24·22 + 11). It opens scrolled to\n            // the day's first event with an hour of context above, or to 7:30a\n            // when empty (SPEC §12-F — the original computed this then never\n            // applied it); clamped so it can't scroll past the day's end.\n            tl: View [ width = { parent.width }, height = 611,\n                y = { 0 - Math.max(0, Math.min(:firstStart * 22 / 60 - 11,\n                          Math.max(0, 611 - parent.height))) },\n                draw(d) {\n                    d.fillStyle = 0xAEB8BF\n                    for (let h = 0; h < 24; h++) d.fillRect(28, h * 22 + 11, this.width - 38, 1)\n                    d.fillStyle = 0x8C9AA3\n                    d.fillRect(28, 0, 1, this.height)\n                    },\n                labels: View [ width = 28,\n                    HourLabel [ datapath = :hours[], y = { :y - 6 } ],\n                    ],\n                events: View [ x = 28, width = { parent.width - 38 },\n                    TimeEvent [ datapath = :events[], category = :category,\n                        dayKey = { classroot.dayKey }, selected = { this.root.selectedEvent == :id } ],\n                    ],\n                ],\n\n            // Vertical scrollbar (drawn — the original's vscrollbar was a\n            // 238-line bitmap widget): a track down the right edge with a thumb\n            // sized by viewport/content and placed by the current scroll.\n            bar: View [ x = { parent.width - 10 }, width = 10, height = { parent.height },\n                visible = { 611 > parent.height },\n                draw(d) {\n                    d.fillStyle = 0x46606F\n                    d.fillRect(0, 0, this.width, this.height)\n                    const th = Math.max(20, this.height * this.height / 611)\n                    const maxS = Math.max(1, 611 - this.height)\n                    const ty = (0 - parent.tl.y) / maxS * (this.height - th)\n                    d.fillStyle = 0x9BAAB3\n                    d.fillRect(1, ty, this.width - 2, th)\n                    },\n                ],\n            ],\n        ],\n    ]\n\n\n// ── DayName — a weekday column title, tracking its column's live geometry ───\n// Bound to the `cols` records relayout maintains (x/width per column, per\n// mode) — the original constrained each label to its top-row CELL for the\n// same effect. Day mode shows only the open day's label (SPEC §12-D).\n\nclass DayName extends View [\n    t: Text [ fontSize = 10, fontWeight = bold, textColor = #B7BEC1,\n        x = { (parent.width - this.width) / 2 }, text = :label ],\n    ]\n\n\n// ── CalendarGrid — the grid layout (SPEC §2), a custom layout in Declare ────\n// Extends TweenLayout: the layout OWNS every cell's x/y/width/height/visible\n// and glides them between two whole layouts through one scalar `t` (the\n// original's gridsliderlayout idiom, rebuilt declaratively). `place()` is the\n// pure geometry — cell box = fn(mode, focus col/row, rows, W, H) with the SPEC\n// §2 open-redistribution; the App sets mode/focus and calls retarget(animate)\n// (snap vs slide) on a geometry-affecting change. duration inherits TweenLayout's\n// 500ms (SPEC §11).\n\nclass CalendarGrid extends TweenLayout [\n    mode: string = \"month\",\n    focusCol: number = -1,          // open/selected column (-1 = none)\n    focusRow: number = -1,          // open/selected row    (-1 = none)\n    rows: number = 5,\n    openW: number = 150,            // SPEC §2: open cell +150w / +170h, redistributed\n    openH: number = 170,\n\n    // per-column widths / per-row heights, then prefix-summed to origins\n    geom() {\n        const W = this.view.width, H = this.view.height, rows = this.rows, sp = 4\n        const cw = Math.floor((W - sp * 6) / 7)\n        const ch = Math.floor((H - sp * (rows - 1)) / rows)\n        const colW = [], rowH = []\n        for (let c = 0; c < 7; c++)\n            colW.push(this.mode == \"day\" ? (c == this.focusCol ? W - sp : 0)\n                    : this.focusCol < 0  ? cw\n                    :                      c == this.focusCol ? cw + this.openW : cw - Math.floor(this.openW / 6))\n        for (let r = 0; r < rows; r++)\n            rowH.push(this.mode != \"month\" ? (r == this.focusRow ? H : 0)\n                    : this.focusRow < 0    ? ch\n                    :                        r == this.focusRow ? ch + this.openH : ch - Math.floor(this.openH / (rows - 1)))\n        const colX = [0], rowY = [0]\n        for (let c = 1; c < 7; c++) colX.push(colX[c - 1] + colW[c - 1] + (colW[c - 1] > 0 ? sp : 0))\n        for (let r = 1; r < rows; r++) rowY.push(rowY[r - 1] + rowH[r - 1] + (rowH[r - 1] > 0 ? sp : 0))\n        return { colX: colX, colW: colW, rowY: rowY, rowH: rowH }\n        },\n\n    // one box per laid cell (SPEC §2). Same laid() order the base owns slots in.\n    place() {\n        const g = this.geom(), rows = this.rows\n        return this.laid().map((c, i) => {\n            const col = i % 7, row = Math.floor(i / 7)\n            const w = g.colW[col], h = row < rows ? g.rowH[row] : 0\n            return { x: g.colX[col], y: row < rows ? g.rowY[row] : 0, w: w, h: h, vis: w > 0 && h > 0 }\n            })\n        },\n\n    // the seven day-name column boxes (day mode shows only the focus column)\n    colBoxes() {\n        const g = this.geom()\n        const names = [\"Sunday\", \"Monday\", \"Tuesday\", \"Wednesday\", \"Thursday\", \"Friday\", \"Saturday\"]\n        const out = []\n        for (let c = 0; c < 7; c++)\n            out.push({ label: names[c], x: g.colX[c], w: g.colW[c],\n                       vis: this.mode == \"day\" ? c == this.focusCol : true })\n        return out\n        },\n    ]\n\n\n// ── CalButton — the pill button, drawn (SPEC §13: kills the button slices) ──\n// Gradient face, rounded caps, white bold label; pressed = darker face.\n// (Hover feedback waits for the hover rung.)\n\nclass CalButton extends View [\n    label: string = \"\",\n    down: boolean = false,\n    height = 17,\n    cornerRadius = 8,\n\n    fill = { this.down\n        ? gradient(stop(0, 0x8FA0A6), stop(0.35, 0x7D8E96), stop(1, 0x4E626E))\n        : gradient(stop(0, 0xD9DFDF), stop(0.35, 0xB4BDBF), stop(1, 0x5C717D)) },\n    stroke = stroke(1, #143B45),\n\n    caption: Text [ fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n        x = { (parent.width - this.width) / 2 }, y = 3,\n        textShadow = shadow(0, -1, 0, #33555577),\n        text = { classroot.label } ],\n\n    onMouseDown() { this.down = true },\n    onMouseUp()   { this.down = false },\n    ]\n\n\n// ── the app ─────────────────────────────────────────────────────────────────\n\nApp [ width = 835, height = 600, fill = #1E3A49,\n    fontFamily = [Cal, \"Geneva\", \"sans-serif\"], fontSize = 10, fontWeight = normal, textColor = #FFFFFF,\n\n    // ── the store (SPEC §9) ──\n    // All months' events in one fetch (the original lazy-loaded per-month XML;\n    // the corpus is tiny and edits are in-memory by scope). `cal.days` is the\n    // displayed month: one record per visible day, events pre-sorted; `cal.cols`\n    // is the seven column boxes relayout maintains for the day-name labels.\n\n    data: DataSource [ url = \"data/events.json\" ],\n    cal: Dataset { { \"days\": [], \"cols\": [] } },\n\n    year: number = 0,\n    month: number = 0,                    // 1-based, like the data\n    rows: number = 5,\n    selectedKey: string = \"\",\n    selectedEvent: number = -1,           // the selected event's id, or -1\n    panelOpen: boolean = false,           // the info panel is showing (SPEC §7)\n    newEvent: boolean = false,            // panel opened on a just-added event…\n    applied: boolean = false,             // …and whether it has been Apply'd\n    openTab: number = 0,                  // accordion: 0 Notes / 1 Location / 2 Attendees\n    dragId: number = -1,                  // event being dragged, or -1 (SPEC §6)\n    dragArmed: boolean = false,           // moved since press → a drag, not a click\n    dragOccurred: boolean = false,        // a drag just finished → swallow the click\n    dragOverKey: string = \"\",             // day cell under the pointer (hilite)\n    dragX: number = 0,                    // last pointer position, app-relative\n    dragY: number = 0,\n\n    // the view-mode state machine (SPEC §2): month | week | day, plus the\n    // orthogonal open day (in-place expanded in month, widened column in week)\n    mode: string = \"month\",\n    openKey: string = \"\",\n\n    monthName(m) {\n        return [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\"July\",\n                \"August\",\"September\",\"October\",\"November\",\"December\"][m - 1]\n        },\n\n    shortTime(min) {\n        const h = Math.floor(min / 60)\n        return (h == 0 ? 12 : h > 12 ? h - 12 : h) + (h > 11 ? \"p\" : \"a\")\n        },\n\n    keyOf(dt) {\n        return dt.getFullYear() + \"-\" + (dt.getMonth() + 1) + \"-\" + dt.getDate()\n        },\n\n    parseKey(key) {\n        const p = key.split(\"-\").map(Number)\n        return new Date(p[0], p[1] - 1, p[2])\n        },\n\n    // Build the displayed month: 35 or 42 day records starting the Sunday of\n    // the week containing the 1st (SPEC §2). Each record carries its events,\n    // sorted by start. Selection: an explicit key (mode-aware nav), else\n    // today when visible, else the 1st (§12-A).\n    setMonth(y, m, selKey) {\n        this.year = y\n        this.month = m\n        const first = new Date(y, m - 1, 1)\n        const start = new Date(y, m - 1, 1 - first.getDay())\n        const daysInMonth = new Date(y, m, 0).getDate()\n        this.rows = Math.ceil((first.getDay() + daysInMonth) / 7)\n\n        const all = this.data.value != null ? this.data.value.events : []\n        const hours = this.buildHours()    // shared ref: the open timeline's gutter\n        const days = []\n        for (let i = 0; i < this.rows * 7; i++) {\n            const dt = new Date(start.getFullYear(), start.getMonth(), start.getDate() + i)\n            const events = all\n                .filter(e => e.y == dt.getFullYear() && e.m == dt.getMonth() + 1 && e.d == dt.getDate())\n                .sort((a, b) => a.start - b.start || b.id - a.id)\n                .map(e => Object.assign({}, e, { timeLabel: this.shortTime(e.start) }))\n            this.assignLanes(events)\n            days.push({\n                key: this.keyOf(dt),\n                num: dt.getDate(),\n                col: i % 7,\n                row: Math.floor(i / 7),\n                inMonth: dt.getMonth() == m - 1,\n                weekend: dt.getDay() == 0 || dt.getDay() == 6,\n                events: events,\n                hours: hours,\n                firstStart: events.length > 0 ? events[0].start : 450,\n                })\n            }\n        this.cal.set(\"days\", days)\n\n        if (selKey != null) this.selectedKey = selKey\n        else {\n            const now = new Date()\n            this.selectedKey = (now.getFullYear() == y && now.getMonth() == m - 1)\n                ? this.keyOf(now) : y + \"-\" + m + \"-1\"\n            }\n        this.relayout(false)              // cells that already exist re-place now;\n        },                                // fresh ones place on arrival (cellArrived)\n\n    // ── the mode machine ──\n    // Original semantics kept: opening in month SNAPS (gridslider disables\n    // animation in grid mode); widening in week and every mode switch SLIDE.\n\n    openDay(key) {\n        this.selectedKey = key\n        if (this.mode == \"day\") return\n        // Month: open in place (timeline). Week: a plain click only selects and\n        // keeps the column a list — the `+` chrome is what opens it (SPEC §6).\n        if (this.mode == \"month\") this.openKey = key\n        this.relayout(this.mode == \"week\")\n        },\n\n    showMonth() {\n        const animate = this.mode != \"month\"\n        this.mode = \"month\"\n        this.openKey = \"\"\n        this.relayout(animate)\n        },\n\n    // The `−` button: day view → back to month; an open month/week cell → close\n    // it in place (SPEC §6).\n    closeDay() {\n        if (this.mode == \"day\") this.showMonth()\n        else { this.openKey = \"\"; this.relayout(this.mode == \"week\") }\n        },\n\n    showWeek() {\n        const animate = this.mode != \"week\"\n        this.mode = \"week\"\n        this.openKey = \"\"                 // entering week closes the open day\n        this.relayout(animate)            // (the original's showrow)\n        },\n\n    showDay() {\n        this.mode = \"day\"\n        this.openKey = this.selectedKey\n        this.relayout(true)\n        },\n\n    // Mode-aware navigation (SPEC §12-B: the original jumped a month from any\n    // mode and snapped back to month view — fixed): month steps a month, week\n    // a week, day a day; the mode is preserved. Navigation snaps (§11).\n    step(dir) {\n        if (this.mode == \"month\") {\n            const wrap = this.month == (dir > 0 ? 12 : 1)\n            this.setMonth(wrap ? this.year + dir : this.year,\n                          wrap ? (dir > 0 ? 1 : 12) : this.month + dir)\n            return\n            }\n        const d = this.parseKey(this.selectedKey)\n        d.setDate(d.getDate() + dir * (this.mode == \"week\" ? 7 : 1))\n        const key = this.keyOf(d)\n        if (this.mode == \"day\") this.openKey = key\n        if (d.getFullYear() != this.year || d.getMonth() + 1 != this.month) {\n            this.setMonth(d.getFullYear(), d.getMonth() + 1, key)\n            }\n        else {\n            this.selectedKey = key\n            this.relayout(false)\n            }\n        },\n\n    // ── the grid layout bridge (SPEC §2) ──\n    // Geometry now lives in the grid's CalendarGrid layout; this pushes the\n    // App's mode + focus col/row (known from the selection / open day and the\n    // day records) onto the layout, retargets it (animate = slide, else snap),\n    // and refreshes the day-name columns from the layout's own geometry. Cell\n    // arrival is handled by the layout itself (childrenMutated → re-arm).\n    relayout(animate) {\n        const L = this.grid.layout\n        if (L == null) return\n        L.rows = this.rows\n        L.mode = this.mode\n        let fCol = -1, fRow = -1\n        if (this.mode == \"month\") {\n            if (this.openKey != \"\") { const p = this.cellPos(this.openKey); fCol = p.col; fRow = p.row }\n            }\n        else {\n            const p = this.cellPos(this.selectedKey); fRow = p.row\n            if (this.mode == \"day\") fCol = p.col\n            }\n        L.focusCol = fCol\n        L.focusRow = fRow\n        L.retarget(animate)\n        this.cal.set(\"cols\", L.colBoxes())\n        },\n\n    // a day key's grid position (col/row) in the displayed month, or -1/-1\n    cellPos(key) {\n        for (const rec of this.cal.value.days) {\n            if (rec.key == key) return { col: rec.col, row: rec.row }\n            }\n        return { col: -1, row: -1 }\n        },\n\n    // A cell is \"open\" (hour timeline, not the list) iff it is THE open day —\n    // set when a month cell opens in place, when `+` opens a week column, or on\n    // entering day view. Other week/month cells stay closed lists (SPEC §3).\n    isOpen(key) {\n        return key != \"\" && key == this.openKey\n        },\n\n    // Click an event → select its day AND the event; does NOT open the day\n    // (SPEC §6). The DayCell/event `selected` bindings react to the two keys.\n    selectEvent(id, key) {\n        this.selectedKey = key\n        this.selectedEvent = id\n        if (this.panelOpen) this.syncPanelFields()   // retarget the open panel (§5)\n        },\n\n    // ── event drag (SPEC §6) ──\n    // A press arms nothing; the first move makes it a drag (so a plain click\n    // never moves the bar). The day cell under the pointer hilites; dropping on\n    // a day moves the event there (same time), selecting that day. A drag\n    // swallows the click that the router pairs with the release.\n    catFill(cat) {\n        return cat == \"holiday\" ? 0xCBD1C5 : cat == \"astro\" ? 0xC5C3D5\n             : cat == \"milestone\" ? 0xBBC6D1 : 0xC6CEDC\n        },\n    startDrag(id) {\n        this.dragId = id\n        this.dragArmed = false\n        this.dragOccurred = false\n        const e = this.srcEvent(id)          // dress the ghost that follows the pointer\n        if (e != null) {\n            this.dragGhost.label.text = e.title\n            this.dragGhost.fill = this.catFill(e.category)\n            }\n        },\n    dragMove(rx, ry) {\n        if (this.dragId < 0) return\n        this.dragArmed = true\n        this.dragX = rx\n        this.dragY = ry\n        this.dragOverKey = this.dayAtPoint(rx, ry)\n        },\n    endDrag() {\n        if (this.dragId < 0) return\n        if (this.dragArmed) {\n            this.dragOccurred = true\n            const key = this.dayAtPoint(this.dragX, this.dragY)\n            if (key != \"\") this.dropEvent(this.dragId, key)\n            }\n        this.dragId = -1\n        this.dragArmed = false\n        this.dragOverKey = \"\"\n        },\n    dropEvent(id, key) {\n        const e = this.srcEvent(id)\n        if (e == null) return\n        const d = this.parseKey(key)\n        const dur = e.end - e.start\n        e.y = d.getFullYear(); e.m = d.getMonth() + 1; e.d = d.getDate()\n        // Dropping on an OPEN day sets the time from the drop-y (15-min snap,\n        // duration preserved, end ≤ 23:45 — SPEC §6 time-drag).\n        if (this.isOpen(key)) {\n            const t = this.timeAtPoint(key, this.dragY)\n            if (t >= 0) { e.start = Math.max(0, Math.min(t, 1425)); e.end = e.start + dur }\n            }\n        this.setMonth(this.year, this.month, key)     // selects the target day\n        this.selectedEvent = id\n        },\n\n    // The 15-min-snapped minute-of-day at an app-relative y inside an open day's\n    // timeline (accounts for the cell box and its scroll), or -1.\n    timeAtPoint(key, ry) {\n        for (const c of this.grid.children) {\n            if (c.dayKey == key && c.body != null && c.body.tl != null) {\n                const contentY = (ry - 57 - c.y - 19) - c.body.tl.y\n                return Math.round(((contentY - 11) / 22 * 60) / 15) * 15\n                }\n            }\n        return -1\n        },\n\n    // The day key whose (live) cell box contains an app-relative point, or \"\".\n    dayAtPoint(rx, ry) {\n        const gx = rx - 20, gy = ry - 57              // grid sits at (20, 57)\n        for (const c of this.grid.children) {\n            if (c.dayKey != null && c.visible\n                && gx >= c.x && gx < c.x + c.width\n                && gy >= c.y && gy < c.y + c.height) return c.dayKey\n            }\n        return \"\"\n        },\n\n    // The ⓘ button / double-click opens the info panel on an event (SPEC §7).\n    showInfo(id) {\n        this.selectedEvent = id\n        this.newEvent = false\n        this.openPanel()\n        },\n\n    // Open: grid contracts (snap −208), panel slides x852→622 + fades (500ms).\n    openPanel() {\n        this.panelOpen = true\n        this.grid.width = 600\n        this.relayout(false)\n        this.infoPanel.slideIn.start()\n        this.syncPanelFields()\n        },\n\n    // Close. A panel opened by Add Event on an unapplied new event deletes it on\n    // cancel (SPEC §7 cancel semantics); the grid re-expands (snap).\n    closePanel() {\n        if (this.newEvent && !this.applied) this.deleteEvent()\n        this.panelOpen = false\n        this.newEvent = false\n        this.grid.width = 808\n        this.relayout(false)\n        this.infoPanel.slideOut.start()\n        },\n\n    // The selected event's DISPLAY record (reactive over the store), or null.\n    selRec() {\n        if (this.selectedEvent < 0) return null\n        for (const day of this.cal.value.days)\n            for (const e of day.events)\n                if (e.id == this.selectedEvent) return e\n        return null\n        },\n\n    // The selected event's SOURCE record (what edits mutate; the display copies\n    // are re-derived by setMonth). Edits are in-memory only (SPEC §9).\n    srcEvent(id) {\n        return this.data.value.events.find(e => e.id == id)\n        },\n\n    longDate(rec) {\n        return rec != null ? this.monthName(rec.m) + \" \" + rec.d + \", \" + rec.y : \"\"\n        },\n\n    longTime(min) {\n        const h = Math.floor(min / 60), m = min % 60\n        return (h == 0 ? 12 : h > 12 ? h - 12 : h) + \":\"\n             + (m < 10 ? \"0\" + m : \"\" + m) + (h > 11 ? \"p\" : \"a\")\n        },\n\n    setTab(i) { this.openTab = i },\n\n    // Add Event (SPEC §8): a 9–10a \"New Event\" on the selected day, selected and\n    // opened in the panel. Closing without Apply deletes it (cancel semantics).\n    addEvent() {\n        const es = this.data.value.events\n        const id = 1 + es.reduce((mx, e) => Math.max(mx, e.id), 0)\n        const d = this.parseKey(this.selectedKey)\n        es.push({ id: id, y: d.getFullYear(), m: d.getMonth() + 1, d: d.getDate(),\n                  start: 540, end: 600, title: \"New Event\",\n                  notes: \"\", location: \"\", attendees: \"\", category: \"\" })\n        this.setMonth(this.year, this.month, this.selectedKey)\n        this.selectedEvent = id\n        this.newEvent = true\n        this.applied = false\n        this.openPanel()\n        },\n\n    // Push the selected event's text into the (editable, unbound) panel fields —\n    // on open and on retarget. Date/times stay bound to the record (spinners).\n    syncPanelFields() {\n        const e = this.selRec()\n        if (e == null) return\n        this.infoPanel.titleF.text = e.title\n        this.infoPanel.notesSec.area.text = e.notes != null ? e.notes : \"\"\n        this.infoPanel.locSec.area.text = e.location != null ? e.location : \"\"\n        this.infoPanel.attSec.area.text = e.attendees != null ? e.attendees : \"\"\n        },\n\n    // Apply commits the four text fields from the panel (SPEC §7).\n    apply() {\n        this.applyText(this.infoPanel.titleF.text, this.infoPanel.notesSec.area.text,\n                       this.infoPanel.locSec.area.text, this.infoPanel.attSec.area.text)\n        },\n\n    // Commit the text fields (title/notes/location/attendees) — Apply (SPEC §7).\n    applyText(title, notes, location, attendees) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        e.title = title; e.notes = notes; e.location = location; e.attendees = attendees\n        this.applied = true\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // Date ‹›: move the event ±1 day (crosses months by navigating — SPEC §7).\n    moveDay(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        const d = new Date(e.y, e.m - 1, e.d + delta)\n        e.y = d.getFullYear(); e.m = d.getMonth() + 1; e.d = d.getDate()\n        this.setMonth(e.y, e.m, this.keyOf(d))\n        },\n\n    // Start ‹›: ±15m MOVES the event (duration preserved), end clamped ≤ 23:45.\n    moveStart(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        const dur = e.end - e.start\n        e.start = Math.max(0, Math.min(e.start + delta, 1425))\n        e.end = e.start + dur\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // Dispatch a Stepper's nudge to the right edit (SPEC §7).\n    stepField(field, dir) {\n        if (field == \"date\") this.moveDay(dir)\n        else if (field == \"start\") this.moveStart(dir * 15)\n        else this.moveEnd(dir * 15)\n        },\n\n    // End ‹›: ±15m CHANGES duration (min 15m, max < 24h — SPEC §7).\n    moveEnd(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        e.end = Math.max(e.start + 15, Math.min(e.end + delta, 1439))\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    deleteEvent() {\n        const es = this.data.value.events\n        const i = es.findIndex(e => e.id == this.selectedEvent)\n        if (i >= 0) es.splice(i, 1)\n        this.selectedEvent = -1\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // The 24 hour-gutter markers for the open timeline (SPEC §3): number, am/pm,\n    // the y of its hour rule (22px/hour, +11px half-hour zero), bold on 12a/12p.\n    buildHours() {\n        const hours = []\n        for (let h = 0; h < 24; h++)\n            hours.push({ num: \"\" + (h % 12 == 0 ? 12 : h % 12),\n                         ampm: h < 12 ? \"a\" : \"p\", y: h * 22 + 11, bold: h % 12 == 0 })\n        return hours\n        },\n\n    // Side-by-side lanes for overlapping open-timeline events (SPEC §12-E, fix).\n    // `events` is start-sorted; each disjoint cluster shares its own lane count\n    // so non-overlapping events stay full width (lane 0 of 1).\n    assignLanes(events) {\n        const flush = (cluster) => {\n            const laneEnd = []\n            for (const e of cluster) {\n                let ln = 0\n                while (ln < laneEnd.length && laneEnd[ln] > e.start) ln++\n                laneEnd[ln] = e.end\n                e.lane = ln\n                }\n            for (const e of cluster) e.lanes = laneEnd.length\n            }\n        let cluster = [], clusterEnd = 0\n        for (const e of events) {\n            if (cluster.length > 0 && e.start >= clusterEnd) { flush(cluster); cluster = []; clusterEnd = 0 }\n            cluster.push(e)\n            clusterEnd = Math.max(clusterEnd, e.end)\n            }\n        if (cluster.length > 0) flush(cluster)\n        },\n\n    // Startup (SPEC §10): once data is in, the top panel slides down and the\n    // grid fades up (the loading-still → panel → grid reveal).\n    onInit() {\n        this.data.fetch().then(() => {\n            const now = new Date()\n            this.setMonth(now.getFullYear(), now.getMonth() + 1)\n            this.top.slideDown.start()\n            this.grid.fadeIn.start()\n            })\n        },\n\n    // ── top panel (SPEC §1) ──\n\n    top: View [ x = 20, width = 806, y = -50,\n        slideDown: Animator [ attribute = y, to = 0, duration = 500, motion = laszloBoth ],\n\n        // the daynames bar sits behind the menubar strip (original stacking)\n        weekbar: View [ y = 26, width = 808, height = 26, fill = #354D5B,\n            datapath = { classroot.cal.value },\n            rule: View [ y = 25, width = { parent.width }, height = 1, fill = #708A94 ],\n\n            names: View [ y = 11, width = { parent.width }, height = 12,\n                DayName [ datapath = :cols[], x = :x, width = :w, height = 12, visible = :vis ],\n                ],\n            ],\n\n        mbar: View [ width = 806, height = 32,\n            strip: Image [ source = \"resources/mainbar-overlay.png\" ],\n            logo:  Image [ source = \"resources/logo.png\" ],\n\n            viewBtns: View [ x = 142, y = 4, width = 174, height = 17, cornerRadius = 8,\n                fill = gradient(stop(0, 0xD9DFDF), stop(0.35, 0xB4BDBF), stop(1, 0x5C717D)),\n                stroke = stroke(1, #143B45),\n\n                // segment separators + the three tiny icons, drawn\n                draw(d) {\n                    d.fillStyle = 0x143B45\n                    d.fillRect(47, 0, 1, this.height)\n                    d.fillRect(104, 0, 1, this.height)\n                    // day: a page outline\n                    d.fillRect(8, 5, 8, 1); d.fillRect(8, 12, 8, 1)\n                    d.fillRect(8, 5, 1, 8); d.fillRect(15, 5, 1, 8)\n                    // week: four bars\n                    d.fillRect(55, 5, 2, 8); d.fillRect(58, 5, 2, 8)\n                    d.fillRect(61, 5, 2, 8); d.fillRect(64, 5, 2, 8)\n                    // month: a 3×3 dot grid\n                    d.fillRect(112, 5, 2, 2); d.fillRect(115, 5, 2, 2); d.fillRect(118, 5, 2, 2)\n                    d.fillRect(112, 8, 2, 2); d.fillRect(115, 8, 2, 2); d.fillRect(118, 8, 2, 2)\n                    d.fillRect(112, 11, 2, 2); d.fillRect(115, 11, 2, 2); d.fillRect(118, 11, 2, 2)\n                    },\n\n                dayLbl:   Text [ x = 20,  y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"day\" ],\n                weekLbl:  Text [ x = 69,  y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"week\" ],\n                monthLbl: Text [ x = 124, y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"month\" ],\n\n                dayHit:   View [ x = 0,   width = 47, height = 17, onClick() { classroot.showDay() } ],\n                weekHit:  View [ x = 47,  width = 57, height = 17, onClick() { classroot.showWeek() } ],\n                monthHit: View [ x = 104, width = 70, height = 17, onClick() { classroot.showMonth() } ],\n                ],\n\n            monthCtl: View [ x = 321, y = 8, width = 161, height = 17, cornerRadius = 8,\n                fill = gradient(stop(0, 0xBBC3C5), stop(0.4, 0xC5CCCF), stop(1, 0x7A8B94)),\n                stroke = stroke(1, #24424F),\n\n                // the segment separators: incised VERTICAL grooves (dark line\n                // + a highlight one px to its right), dividing the arrow caps\n                // from the title — oracle-measured at x16 / x142.\n                draw(d) {\n                    d.fillStyle = 0x143B45\n                    d.fillRect(16, 0, 1, 17)\n                    d.fillRect(142, 0, 1, 17)\n                    d.fillStyle = 0xD9DFDF\n                    d.fillRect(17, 0, 1, 17)\n                    d.fillRect(143, 0, 1, 17)\n                    // the cap arrows\n                    d.fillStyle = 0xFFFFFF\n                    d.beginPath()\n                    d.moveTo(14, 4); d.lineTo(7, 8.5); d.lineTo(14, 13)\n                    d.fill()\n                    d.beginPath()\n                    d.moveTo(147, 4); d.lineTo(154, 8.5); d.lineTo(147, 13)\n                    d.fill()\n                    },\n\n                prevBtn: View [ width = 24, height = 17, onClick() { classroot.step(-1) } ],\n                nextBtn: View [ x = 137, width = 24, height = 17, onClick() { classroot.step(1) } ],\n                ],\n\n            // bold white centered title with the drop shadow the original\n            // faked with a second offset text view — here one textShadow.\n            monthTitle: Text [ y = 10, fontWeight = bold, textColor = #FFFFFF,\n                x = { (parent.width - this.width) / 2 - 2 },\n                textShadow = shadow(0, -1, 0, #143B4580),\n                text = { classroot.month > 0 ? classroot.monthName(classroot.month) + \" \" + classroot.year : \"\" } ],\n\n            addBtn: CalButton [ x = 496, y = 5, width = 76, label = \"Add Event\",\n                onClick() { classroot.addEvent() } ],\n            ],\n        ],\n\n    // ── the grid (SPEC §2) ──\n\n    grid: View [ x = 20, y = 57, width = 808, height = 516, opacity = 0,\n        fadeIn: Animator [ attribute = opacity, to = 1, duration = 1000, motion = laszloBoth ],\n        datapath = { classroot.cal.value },\n        layout: CalendarGrid [ ],\n\n        DayCell [ datapath = :days[], dayKey = :key,\n            selected = { classroot.selectedKey == this.dayKey },\n            open = { classroot.isOpen(this.dayKey) },\n            onClick() { classroot.openDay(this.dayKey) } ],\n        ],\n\n    // ── the info panel (SPEC §7) — slides in from the right over the grid ────\n    // Beveled body drawn in neo (the original was 9-slice bitmaps); bound to the\n    // selected event's record; date/time ‹› nudges edit it live.\n\n    infoPanel: View [ x = 852, y = 57, width = 205, height = 516, opacity = 0,\n        visible = { this.opacity > 0 },\n        datapath = { classroot.selRec() },\n        fill = #C6CAC4,\n        stroke = stroke(1, #83877F),\n\n        slideIn:  AnimatorGroup [ process = simultaneous, duration = 500, motion = laszloBoth,\n            Animator [ attribute = x, to = 622 ],\n            Animator [ attribute = opacity, to = 1 ] ],\n        slideOut: AnimatorGroup [ process = simultaneous, duration = 500, motion = laszloBoth,\n            Animator [ attribute = x, to = 852 ],\n            Animator [ attribute = opacity, to = 0 ] ],\n\n        bar: View [ width = { parent.width }, height = 18, fill = #384852,\n            cap: Text [ x = 8, y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                        text = \"Event Info\" ],\n            xbtn: View [ x = { parent.width - 15 }, y = 4, width = 11, height = 11,\n                draw(d) {\n                    d.fillStyle = 0xFFFFFF\n                    d.lineWidth = 1.5\n                    d.beginPath(); d.moveTo(2, 2); d.lineTo(9, 9)\n                    d.moveTo(9, 2); d.lineTo(2, 9); d.stroke()\n                    },\n                onClick() { this.root.closePanel() } ],\n            ],\n\n        titleF: TextInput [ x = 6, y = 24, width = 193, height = 17, fill = #FFFFFF,\n            fontSize = 11, textColor = #333333 ],\n\n        dateStep:  Stepper [ x = 8, y = 47, width = 189, field = \"date\",\n            label = { this.root.monthName(:m) + \" \" + :d + \", \" + :y } ],\n        startStep: Stepper [ x = 8, y = 66, width = 82, field = \"start\",\n            label = { this.root.longTime(:start) } ],\n        toLbl:     Text [ x = 94, y = 68, fontSize = 10, textColor = #2E3E48, text = \"to\" ],\n        endStep:   Stepper [ x = 115, y = 66, width = 82, field = \"end\",\n            label = { this.root.longTime(:end) } ],\n\n        notesSec: AccordionSection [ x = 4, idx = 0, label = \"Notes\" ],\n        locSec:   AccordionSection [ x = 4, idx = 1, label = \"Location\" ],\n        attSec:   AccordionSection [ x = 4, idx = 2, label = \"Attendees\" ],\n\n        applyBtn:  CalButton [ x = 8, y = 486, width = 82, label = \"Apply\",\n            onClick() { this.root.apply() } ],\n        deleteBtn: CalButton [ x = 115, y = 486, width = 82, label = \"Delete\",\n            onClick() { this.root.deleteEvent(); this.root.closePanel() } ],\n        ],\n\n    // A ghost of the dragged event that follows the pointer (SPEC §6) — the top\n    // layer, shown once a press turns into a drag. Its label/fill are dressed in\n    // startDrag; x/y track the app-relative pointer.\n    dragGhost: View [ visible = { classroot.dragId >= 0 && classroot.dragArmed },\n        x = { classroot.dragX - 10 }, y = { classroot.dragY - 9 },\n        width = 132, height = 18, opacity = 0.82, cornerRadius = 3,\n        fill = #C6CEDC, stroke = stroke(1, #8A98A4),\n        label: Text [ x = 7, y = 3, fontSize = 10, textColor = #3A4650, text = \"\" ],\n        ],\n    ]\n","pageWeight":58,"sourceLines":752,"seeds":{"__page__":"// neocalendar — the Laszlo Calendar rewritten from the ground up in Declare.\n// The contract is SPEC.md (extracted from the running original + its source\n// read for intent); this file implements the spec, not the original's\n// structure. Stage 3: the three view modes (month / week / day) + the open\n// day, with the 500ms slider motion; mode-aware navigation (SPEC §12 B–D).\n// Grid geometry is exact; chrome is drawn (no images except the logo/menubar\n// holdouts) — \"geometry exact, chrome or better\".\n\nfont Cal [ family = \"Verdana\" ]\n\n\n// ── colors (SPEC §3–4; sampled + source-verified) ────────────────────────────\n// Day-cell bodies: weekday #9BA9B1 · weekend #879BA8 · out-of-month #768A97 ·\n// selected/hilite #D3D3D3. Event categories: default/holiday/astro/milestone.\n\n\n// ── EventBar — one event in a day's closed list (SPEC §4) ───────────────────\n// A 22px bar: category fill, 1px white top hairline + #555 bottom (drawn),\n// short time (\"9a\") then title. The open/timeline form arrives in Stage 4.\n\nclass EventBar extends View [\n    width = { parent.width }, height = 22,\n    clip = true,\n\n    category: string = \"\",\n    selected: boolean = false,\n    dayKey: string = \"\",\n\n    // Selected: the bar goes near-white with a category-tinted grip texture and\n    // an ⓘ button (SPEC §5 selector chrome); a click selects day + event (§6).\n    fill = { selected ? 0xFAFAFA\n           : category == \"holiday\"   ? 0xCBD1C5\n           : category == \"astro\"     ? 0xC5C3D5\n           : category == \"milestone\" ? 0xBBC6D1\n           :                           0xC6CEDC },\n\n    draw(d) {\n        d.fillStyle = 0xFFFFFF\n        d.fillRect(0, 0, width, 1)\n        d.fillStyle = 0x555555\n        d.fillRect(0, height - 1, width, 1)\n        if (selected) {\n            d.fillStyle = 0x8A98A0\n            for (let gx = 3; gx < width - 3; gx += 4) {\n                d.fillRect(gx, 2, 1, 2); d.fillRect(gx, height - 4, 1, 2)\n                }\n            }\n        },\n\n    info:  InfoButton [ x = 2, y = 4, visible = { classroot.selected } ],\n    time:  Text [ x = { classroot.selected ? 19 : 4 }, y = 6, fontSize = 10,\n                  textColor = #4B5D6C, text = :timeLabel ],\n    title: Text [ x = { parent.time.x + parent.time.width + 5 }, y = 6,\n                  width = { parent.width - this.x - 2 }, fontSize = 10,\n                  textColor = #4B5D6C, text = :title ],\n\n    onMouseDown() { app.startDrag(:id) },\n    onMouseMove(e) { app.dragMove(e.x, e.y) },\n    onMouseUp()   { app.endDrag() },\n    onClick() { if (!app.dragOccurred) app.selectEvent(:id, this.dayKey) },\n    ]\n\n\n// ── InfoButton — the ⓘ on a selected event (opens the info panel, §5/§7) ─────\n// A drawn 14px disc with an italic-ish \"i\"; inherits the event cursor so its\n// click knows which event (:id) to open.\n\nclass InfoButton extends View [\n    width = 14, height = 14, cornerRadius = 7,\n    fill = gradient(stop(0, 0xF4F4F4), stop(1, 0xAEB6BD)),\n    stroke = stroke(1, #7C8A92),\n\n    glyph: Text [ x = 5, y = 2, fontSize = 9, fontWeight = bold,\n                  textColor = #4B5D6C, text = \"i\" ],\n\n    onClick() { app.showInfo(:id) },\n    ]\n\n\n// ── PlusMinus — the corner open/close button of the selected-day chrome (§5) ──\n// `+` opens the selected day in place; `−` (when already open) collapses it /\n// returns to the month. A drawn glyph — the original used button bitmaps.\n\nclass PlusMinus extends View [\n    isOpen: boolean = false,\n    width = 11, height = 11, cornerRadius = 2,\n    fill = gradient(stop(0, 0xE8ECEC), stop(0.5, 0xC2CBCE), stop(1, 0x8A9BA3)),\n    stroke = stroke(1, #46606C),\n\n    draw(d) {\n        d.fillStyle = 0x2E4550\n        d.fillRect(2, 5, 7, 1)               // the bar — both `+` and `−`\n        if (!isOpen) d.fillRect(5, 2, 1, 7)  // the stem — `+` only\n        },\n\n    onClick() {\n        if (isOpen) app.closeDay()\n        else app.openDay(app.selectedKey)\n        },\n    ]\n\n\n// ── Stepper — a value with ‹ › nudges (the info panel's date/time rows, §7) ──\n// `field` picks the action (date = ±1 day; start = ±15m move; end = ±15m\n// duration); `label` is the formatted value, bound at the instance site.\n\nclass Stepper extends View [\n    field: string = \"\",\n    label: string = \"\",\n    width = 120, height = 16,\n    fill = #FFFFFF,\n    stroke = stroke(1, #A8ACA6),\n\n    val: Text [ x = 5, y = 2, fontSize = 10, textColor = #2E3E48, text = { classroot.label } ],\n\n    left: View [ x = { parent.width - 28 }, y = 1, width = 13, height = 14, cornerRadius = 2,\n        fill = gradient(stop(0, 0xE6EAEA), stop(1, 0x99A5AD)),\n        draw(d) { d.fillStyle = 0x33454F\n                  d.beginPath(); d.moveTo(8, 3); d.lineTo(4, 7); d.lineTo(8, 11); d.fill() },\n        onClick() { app.stepField(classroot.field, -1) } ],\n    right: View [ x = { parent.width - 14 }, y = 1, width = 13, height = 14, cornerRadius = 2,\n        fill = gradient(stop(0, 0xE6EAEA), stop(1, 0x99A5AD)),\n        draw(d) { d.fillStyle = 0x33454F\n                  d.beginPath(); d.moveTo(5, 3); d.lineTo(9, 7); d.lineTo(5, 11); d.fill() },\n        onClick() { app.stepField(classroot.field, 1) } ],\n    ]\n\n\n// ── AccordionSection — one collapsible panel tab (Notes/Location/Attendees) ──\n// One open at a time (App.openTab); the open section's multiline field fills the\n// area and pushes the sections below it down (SPEC §7). Header bevel hairlines\n// + a disclosure triangle, drawn.\n\nclass AccordionSection extends View [\n    idx: number = 0,\n    label: string = \"\",\n    width = 197,\n    y = { 90 + this.idx * 20 + (this.idx > app.openTab ? 330 : 0) },\n\n    hdr: View [ width = { parent.width }, height = 20,\n        fill = { app.openTab == classroot.idx ? 0xE2E4DF : 0xEEF0EB },\n        draw(d) {\n            d.fillStyle = 0xFDFFFF; d.fillRect(0, 0, width, 1)\n            d.fillStyle = 0xC6C7C4; d.fillRect(0, height - 1, width, 1)\n            d.fillStyle = 0x5A6A72\n            d.beginPath()\n            if (app.openTab == classroot.idx) {\n                d.moveTo(width - 14, 7); d.lineTo(width - 6, 7); d.lineTo(width - 10, 13)\n                }\n            else { d.moveTo(width - 12, 6); d.lineTo(width - 6, 9.5); d.lineTo(width - 12, 13) }\n            d.fill()\n            },\n        lbl: Text [ x = 6, y = 5, fontSize = 10, textColor = #3A4A50, text = { classroot.label } ],\n        onClick() { app.setTab(classroot.idx) } ],\n\n    area: TextInput [ x = 2, y = 20, width = { parent.width - 4 }, height = 326,\n        multiline = true, fill = #FFFFFF, fontSize = 10, textColor = #333333,\n        visible = { app.openTab == classroot.idx } ],\n    ]\n\n\n// ── HourLabel — one hour marker down the open-timeline's left gutter (SPEC §3)\n// Replicated over the store's `hours` records ({ num, ampm, y, bold }); the\n// number is 10px (bold on 12a/12p), the am/pm a 7px subscript. Centered on the\n// hour rule at :y.\n\nclass HourLabel extends View [\n    num:  Text [ x = 2, fontSize = 10, textColor = #4B5D6C,\n                 fontWeight = { :bold ? \"bold\" : \"normal\" }, text = :num ],\n    ampm: Text [ x = { parent.num.x + parent.num.width }, y = 3, fontSize = 7,\n                 textColor = #4B5D6C, text = :ampm ],\n    ]\n\n\n// ── TimeEvent — an event in the open hour-timeline (SPEC §3–4) ───────────────\n// Positioned/sized by time: y = start·(22/60)+11, height = max(22, dur·22/60).\n// Category fill, a category-tinted time gutter (29px, 30% opacity) at the left,\n// title only (the closed form's leading time is redundant on a timeline).\n\nclass TimeEvent extends View [\n    category: string = \"\",\n    clip = true,\n    selected: boolean = false,\n    dayKey: string = \"\",\n\n    fill = { selected ? 0xFAFAFA\n           : category == \"holiday\"   ? 0xCBD1C5\n           : category == \"astro\"     ? 0xC5C3D5\n           : category == \"milestone\" ? 0xBBC6D1\n           :                           0xC6CEDC },\n\n    // Placed by time; overlapping events share the width by lane (§12-E — the\n    // store hands each event its lane index and the cluster's lane count).\n    y = { :start * 22 / 60 + 11 },\n    height = { Math.max(22, (:end - :start) * 22 / 60) },\n    x = { :lane * (parent.width / :lanes) },\n    width = { parent.width / :lanes },\n\n    draw(d) {\n        if (!selected) {\n            d.fillStyle = category == \"holiday\"   ? \"rgba(88,116,87,0.30)\"\n                        : category == \"astro\"     ? \"rgba(76,94,126,0.30)\"\n                        : category == \"milestone\" ? \"rgba(76,94,126,0.30)\"\n                        :                           \"rgba(93,132,203,0.30)\"\n            d.fillRect(0, 1, 29, height - 2)\n            }\n        d.fillStyle = 0xFFFFFF\n        d.fillRect(0, 0, width, 1)\n        d.fillStyle = 0x555555\n        d.fillRect(0, height - 1, width, 1)\n        if (selected) {\n            d.fillStyle = 0x8A98A0\n            for (let gx = 3; gx < width - 3; gx += 4) {\n                d.fillRect(gx, 2, 1, 2); d.fillRect(gx, height - 4, 1, 2)\n                }\n            }\n        },\n\n    info:  InfoButton [ x = 2, y = 4, visible = { classroot.selected } ],\n    time:  Text [ x = 19, y = 4, fontSize = 10, textColor = #4B5D6C,\n                  visible = { classroot.selected }, text = :timeLabel ],\n    title: Text [ x = { classroot.selected ? 36 : 10 }, y = 4, fontSize = 10,\n                  textColor = #4B5D6C, width = { parent.width - this.x - 2 }, text = :title ],\n\n    onMouseDown() { app.startDrag(:id) },\n    onMouseMove(e) { app.dragMove(e.x, e.y) },\n    onMouseUp()   { app.endDrag() },\n    onClick() { if (!app.dragOccurred) app.selectEvent(:id, this.dayKey) },\n    ]\n\n\n// ── DayCell — one day of the grid (SPEC §3) ─────────────────────────────────\n// Closed form: a drawn frame — day number on the dark strip, body colored by\n// kind, events stacked in start order (the store pre-sorts, so a plain vertical\n// stack IS the sorted list). OPEN form (in place in month, widened column in\n// week, the day view): the closed list gives way to an hour TIMELINE — the\n// `opened` state on the body swaps them, so only open cells build a timeline.\n// Geometry (x/y/width/height/visible) is owned by the grid's CalendarGrid\n// layout, not the cell.\n\nclass DayCell extends View [\n    dayKey: string = \"\",\n    selected: boolean = false,\n    open: boolean = false,\n\n    // The frame, drawn: a 1px #7A949E ring around the #526C7B strip, with the\n    // original's rounded TOP-LEFT corner (r≈5.5 — the `ctl` art; the other\n    // three corners are square, so cornerRadius can't express it).\n    draw(d) {\n        // Selected: the ring lightens to a bevel — the floating selected-day\n        // chrome (SPEC §5); its corner +/- button rides at the top-right.\n        d.fillStyle = selected ? 0xCAD5DA : 0x7A949E\n        d.beginPath()\n        d.moveTo(5.5, 0); d.lineTo(width, 0); d.lineTo(width, height)\n        d.lineTo(0, height); d.lineTo(0, 5.5)\n        d.arc(5.5, 5.5, 5.5, Math.PI, 1.5 * Math.PI, false)\n        d.fill()\n        d.fillStyle = 0x526C7B\n        d.beginPath()\n        d.moveTo(5.5, 1); d.lineTo(width - 1, 1); d.lineTo(width - 1, height - 1)\n        d.lineTo(1, height - 1); d.lineTo(1, 5.5)\n        d.arc(5.5, 5.5, 4.5, Math.PI, 1.5 * Math.PI, false)\n        d.fill()\n        },\n\n    // Geometry (x/y/width/height/visible) is owned by the grid's CalendarGrid\n    // layout — the cell carries none of the slide machinery any more: the\n    // layout glides every cell through one `t`, and the reveal-at-end rule is a\n    // function of t inside the layout, not a per-cell timer here.\n\n    num: Text [ x = 4, y = 4, fontSize = 10,\n        text = { \"\" + :num },\n        textColor = { :inMonth ? 0xDAE3E8 : 0x7E929F } ],\n\n    // The selected-day chrome's corner button: `+` to open, `−` to close.\n    pm: PlusMinus [ x = { parent.width - 14 }, y = 3,\n        visible = { classroot.selected }, isOpen = { classroot.open } ],\n\n    body: View [ x = 3, y = 19, width = { parent.width - 8 }, height = { parent.height - 26 },\n        clip = true,\n        fill = { classroot.selected || app.dragOverKey == classroot.dayKey ? 0xD3D3D3\n               : :inMonth ? (:weekend ? 0x879BA8 : 0x9BA9B1) : 0x768A97 },\n\n        // Closed form: the sorted event list (hidden the moment the cell opens).\n        list: View [ width = { parent.width }, visible = { !classroot.open },\n            layout: SimpleLayout [ axis = y ],\n            EventBar [ datapath = :events[], category = :category,\n                dayKey = { classroot.dayKey }, selected = { app.selectedEvent == :id } ],\n            ],\n\n        // Open form: an hour timeline, built only while the cell is open. The\n        // hour rules are drawn (22px/hour, +11px half-hour zero); labels ride\n        // the store's `hours` records down a 28px gutter; events sit by time.\n        opened: State [ applied = { classroot.open },\n            // The scrolling content (611px = 24·22 + 11). It opens scrolled to\n            // the day's first event with an hour of context above, or to 7:30a\n            // when empty (SPEC §12-F — the original computed this then never\n            // applied it); clamped so it can't scroll past the day's end.\n            tl: View [ width = { parent.width }, height = 611,\n                y = { 0 - Math.max(0, Math.min(:firstStart * 22 / 60 - 11,\n                          Math.max(0, 611 - parent.height))) },\n                draw(d) {\n                    d.fillStyle = 0xAEB8BF\n                    for (let h = 0; h < 24; h++) d.fillRect(28, h * 22 + 11, width - 38, 1)\n                    d.fillStyle = 0x8C9AA3\n                    d.fillRect(28, 0, 1, height)\n                    },\n                labels: View [ width = 28,\n                    HourLabel [ datapath = :hours[], y = { :y - 6 } ],\n                    ],\n                events: View [ x = 28, width = { parent.width - 38 },\n                    TimeEvent [ datapath = :events[], category = :category,\n                        dayKey = { classroot.dayKey }, selected = { app.selectedEvent == :id } ],\n                    ],\n                ],\n\n            // Vertical scrollbar (drawn — the original's vscrollbar was a\n            // 238-line bitmap widget): a track down the right edge with a thumb\n            // sized by viewport/content and placed by the current scroll.\n            bar: View [ x = { parent.width - 10 }, width = 10, height = { parent.height },\n                visible = { 611 > parent.height },\n                draw(d) {\n                    d.fillStyle = 0x46606F\n                    d.fillRect(0, 0, width, height)\n                    const th = Math.max(20, height * height / 611)\n                    const maxS = Math.max(1, 611 - height)\n                    const ty = (0 - parent.tl.y) / maxS * (height - th)\n                    d.fillStyle = 0x9BAAB3\n                    d.fillRect(1, ty, width - 2, th)\n                    },\n                ],\n            ],\n        ],\n    ]\n\n\n// ── DayName — a weekday column title, tracking its column's live geometry ───\n// Bound to the `cols` records relayout maintains (x/width per column, per\n// mode) — the original constrained each label to its top-row CELL for the\n// same effect. Day mode shows only the open day's label (SPEC §12-D).\n\nclass DayName extends View [\n    t: Text [ fontSize = 10, fontWeight = bold, textColor = #B7BEC1,\n        x = { (parent.width - this.width) / 2 }, text = :label ],\n    ]\n\n\n// ── CalendarGrid — the grid layout (SPEC §2), a custom layout in Declare ────\n// Extends TweenLayout: the layout OWNS every cell's x/y/width/height/visible\n// and glides them between two whole layouts through one scalar `t` (the\n// original's gridsliderlayout idiom, rebuilt declaratively). `place()` is the\n// pure geometry — cell box = fn(mode, focus col/row, rows, W, H) with the SPEC\n// §2 open-redistribution; the App sets mode/focus and calls retarget(animate)\n// (snap vs slide) on a geometry-affecting change. duration inherits TweenLayout's\n// 500ms (SPEC §11).\n\nclass CalendarGrid extends TweenLayout [\n    mode: string = \"month\",\n    focusCol: number = -1,          // open/selected column (-1 = none)\n    focusRow: number = -1,          // open/selected row    (-1 = none)\n    rows: number = 5,\n    openW: number = 150,            // SPEC §2: open cell +150w / +170h, redistributed\n    openH: number = 170,\n\n    // per-column widths / per-row heights, then prefix-summed to origins\n    geom() {\n        const W = this.view.width, H = this.view.height, rows = this.rows, sp = 4\n        const cw = Math.floor((W - sp * 6) / 7)\n        const ch = Math.floor((H - sp * (rows - 1)) / rows)\n        const colW = [], rowH = []\n        for (let c = 0; c < 7; c++)\n            colW.push(this.mode == \"day\" ? (c == this.focusCol ? W - sp : 0)\n                    : this.focusCol < 0  ? cw\n                    :                      c == this.focusCol ? cw + this.openW : cw - Math.floor(this.openW / 6))\n        for (let r = 0; r < rows; r++)\n            rowH.push(this.mode != \"month\" ? (r == this.focusRow ? H : 0)\n                    : this.focusRow < 0    ? ch\n                    :                        r == this.focusRow ? ch + this.openH : ch - Math.floor(this.openH / (rows - 1)))\n        const colX = [0], rowY = [0]\n        for (let c = 1; c < 7; c++) colX.push(colX[c - 1] + colW[c - 1] + (colW[c - 1] > 0 ? sp : 0))\n        for (let r = 1; r < rows; r++) rowY.push(rowY[r - 1] + rowH[r - 1] + (rowH[r - 1] > 0 ? sp : 0))\n        return { colX: colX, colW: colW, rowY: rowY, rowH: rowH }\n        },\n\n    // one box per laid cell (SPEC §2). Same laid() order the base owns slots in.\n    place() {\n        const g = this.geom(), rows = this.rows\n        return this.laid().map((c, i) => {\n            const col = i % 7, row = Math.floor(i / 7)\n            const w = g.colW[col], h = row < rows ? g.rowH[row] : 0\n            return { x: g.colX[col], y: row < rows ? g.rowY[row] : 0, w: w, h: h, vis: w > 0 && h > 0 }\n            })\n        },\n\n    // the seven day-name column boxes (day mode shows only the focus column)\n    colBoxes() {\n        const g = this.geom()\n        const names = [\"Sunday\", \"Monday\", \"Tuesday\", \"Wednesday\", \"Thursday\", \"Friday\", \"Saturday\"]\n        const out = []\n        for (let c = 0; c < 7; c++)\n            out.push({ label: names[c], x: g.colX[c], w: g.colW[c],\n                       vis: this.mode == \"day\" ? c == this.focusCol : true })\n        return out\n        },\n    ]\n\n\n// ── CalButton — the pill button, drawn (SPEC §13: kills the button slices) ──\n// Gradient face, rounded caps, white bold label; pressed = darker face.\n// (Hover feedback waits for the hover rung.)\n\nclass CalButton extends View [\n    label: string = \"\",\n    down: boolean = false,\n    height = 17,\n    cornerRadius = 8,\n\n    fill = { down\n        ? gradient(stop(0, 0x8FA0A6), stop(0.35, 0x7D8E96), stop(1, 0x4E626E))\n        : gradient(stop(0, 0xD9DFDF), stop(0.35, 0xB4BDBF), stop(1, 0x5C717D)) },\n    stroke = stroke(1, #143B45),\n\n    caption: Text [ fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n        x = { (parent.width - this.width) / 2 }, y = 3,\n        textShadow = shadow(0, -1, 0, #33555577),\n        text = { label } ],\n\n    onMouseDown() { this.down = true },\n    onMouseUp()   { this.down = false },\n    ]\n\n\n// ── the app ─────────────────────────────────────────────────────────────────\n\nApp [ width = 835, height = 600, fill = #1E3A49,\n    fontFamily = [Cal, \"Geneva\", \"sans-serif\"], fontSize = 10, fontWeight = normal, textColor = #FFFFFF,\n\n    // ── the store (SPEC §9) ──\n    // All months' events in one fetch (the original lazy-loaded per-month XML;\n    // the corpus is tiny and edits are in-memory by scope). `cal.days` is the\n    // displayed month: one record per visible day, events pre-sorted; `cal.cols`\n    // is the seven column boxes relayout maintains for the day-name labels.\n\n    data: DataSource [ url = \"data/events.json\" ],\n    cal: Dataset { { \"days\": [], \"cols\": [] } },\n\n    year: number = 0,\n    month: number = 0,                    // 1-based, like the data\n    rows: number = 5,\n    selectedKey: string = \"\",\n    selectedEvent: number = -1,           // the selected event's id, or -1\n    panelOpen: boolean = false,           // the info panel is showing (SPEC §7)\n    newEvent: boolean = false,            // panel opened on a just-added event…\n    applied: boolean = false,             // …and whether it has been Apply'd\n    openTab: number = 0,                  // accordion: 0 Notes / 1 Location / 2 Attendees\n    dragId: number = -1,                  // event being dragged, or -1 (SPEC §6)\n    dragArmed: boolean = false,           // moved since press → a drag, not a click\n    dragOccurred: boolean = false,        // a drag just finished → swallow the click\n    dragOverKey: string = \"\",             // day cell under the pointer (hilite)\n    dragX: number = 0,                    // last pointer position, app-relative\n    dragY: number = 0,\n\n    // the view-mode state machine (SPEC §2): month | week | day, plus the\n    // orthogonal open day (in-place expanded in month, widened column in week)\n    mode: string = \"month\",\n    openKey: string = \"\",\n\n    monthName(m) {\n        return [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\"July\",\n                \"August\",\"September\",\"October\",\"November\",\"December\"][m - 1]\n        },\n\n    shortTime(min) {\n        const h = Math.floor(min / 60)\n        return (h == 0 ? 12 : h > 12 ? h - 12 : h) + (h > 11 ? \"p\" : \"a\")\n        },\n\n    keyOf(dt) {\n        return dt.getFullYear() + \"-\" + (dt.getMonth() + 1) + \"-\" + dt.getDate()\n        },\n\n    parseKey(key) {\n        const p = key.split(\"-\").map(Number)\n        return new Date(p[0], p[1] - 1, p[2])\n        },\n\n    // Build the displayed month: 35 or 42 day records starting the Sunday of\n    // the week containing the 1st (SPEC §2). Each record carries its events,\n    // sorted by start. Selection: an explicit key (mode-aware nav), else\n    // today when visible, else the 1st (§12-A).\n    setMonth(y, m, selKey) {\n        this.year = y\n        this.month = m\n        const first = new Date(y, m - 1, 1)\n        const start = new Date(y, m - 1, 1 - first.getDay())\n        const daysInMonth = new Date(y, m, 0).getDate()\n        this.rows = Math.ceil((first.getDay() + daysInMonth) / 7)\n\n        const all = App.data.value != null ? App.data.value.events : []\n        const hours = App.buildHours()    // shared ref: the open timeline's gutter\n        const days = []\n        for (let i = 0; i < this.rows * 7; i++) {\n            const dt = new Date(start.getFullYear(), start.getMonth(), start.getDate() + i)\n            const events = all\n                .filter(e => e.y == dt.getFullYear() && e.m == dt.getMonth() + 1 && e.d == dt.getDate())\n                .sort((a, b) => a.start - b.start || b.id - a.id)\n                .map(e => Object.assign({}, e, { timeLabel: App.shortTime(e.start) }))\n            App.assignLanes(events)\n            days.push({\n                key: this.keyOf(dt),\n                num: dt.getDate(),\n                col: i % 7,\n                row: Math.floor(i / 7),\n                inMonth: dt.getMonth() == m - 1,\n                weekend: dt.getDay() == 0 || dt.getDay() == 6,\n                events: events,\n                hours: hours,\n                firstStart: events.length > 0 ? events[0].start : 450,\n                })\n            }\n        this.cal.set(\"days\", days)\n\n        if (selKey != null) this.selectedKey = selKey\n        else {\n            const now = new Date()\n            this.selectedKey = (now.getFullYear() == y && now.getMonth() == m - 1)\n                ? this.keyOf(now) : y + \"-\" + m + \"-1\"\n            }\n        this.relayout(false)              // cells that already exist re-place now;\n        },                                // fresh ones place on arrival (cellArrived)\n\n    // ── the mode machine ──\n    // Original semantics kept: opening in month SNAPS (gridslider disables\n    // animation in grid mode); widening in week and every mode switch SLIDE.\n\n    openDay(key) {\n        this.selectedKey = key\n        if (this.mode == \"day\") return\n        // Month: open in place (timeline). Week: a plain click only selects and\n        // keeps the column a list — the `+` chrome is what opens it (SPEC §6).\n        if (this.mode == \"month\") this.openKey = key\n        this.relayout(this.mode == \"week\")\n        },\n\n    showMonth() {\n        const animate = this.mode != \"month\"\n        this.mode = \"month\"\n        this.openKey = \"\"\n        this.relayout(animate)\n        },\n\n    // The `−` button: day view → back to month; an open month/week cell → close\n    // it in place (SPEC §6).\n    closeDay() {\n        if (this.mode == \"day\") this.showMonth()\n        else { this.openKey = \"\"; this.relayout(this.mode == \"week\") }\n        },\n\n    showWeek() {\n        const animate = this.mode != \"week\"\n        this.mode = \"week\"\n        this.openKey = \"\"                 // entering week closes the open day\n        this.relayout(animate)            // (the original's showrow)\n        },\n\n    showDay() {\n        this.mode = \"day\"\n        this.openKey = this.selectedKey\n        this.relayout(true)\n        },\n\n    // Mode-aware navigation (SPEC §12-B: the original jumped a month from any\n    // mode and snapped back to month view — fixed): month steps a month, week\n    // a week, day a day; the mode is preserved. Navigation snaps (§11).\n    step(dir) {\n        if (this.mode == \"month\") {\n            const wrap = this.month == (dir > 0 ? 12 : 1)\n            this.setMonth(wrap ? this.year + dir : this.year,\n                          wrap ? (dir > 0 ? 1 : 12) : this.month + dir)\n            return\n            }\n        const d = this.parseKey(this.selectedKey)\n        d.setDate(d.getDate() + dir * (this.mode == \"week\" ? 7 : 1))\n        const key = this.keyOf(d)\n        if (this.mode == \"day\") this.openKey = key\n        if (d.getFullYear() != this.year || d.getMonth() + 1 != this.month) {\n            this.setMonth(d.getFullYear(), d.getMonth() + 1, key)\n            }\n        else {\n            this.selectedKey = key\n            this.relayout(false)\n            }\n        },\n\n    // ── the grid layout bridge (SPEC §2) ──\n    // Geometry now lives in the grid's CalendarGrid layout; this pushes the\n    // App's mode + focus col/row (known from the selection / open day and the\n    // day records) onto the layout, retargets it (animate = slide, else snap),\n    // and refreshes the day-name columns from the layout's own geometry. Cell\n    // arrival is handled by the layout itself (childrenMutated → re-arm).\n    relayout(animate) {\n        const L = this.grid.layout\n        if (L == null) return\n        L.rows = this.rows\n        L.mode = this.mode\n        let fCol = -1, fRow = -1\n        if (this.mode == \"month\") {\n            if (this.openKey != \"\") { const p = this.cellPos(this.openKey); fCol = p.col; fRow = p.row }\n            }\n        else {\n            const p = this.cellPos(this.selectedKey); fRow = p.row\n            if (this.mode == \"day\") fCol = p.col\n            }\n        L.focusCol = fCol\n        L.focusRow = fRow\n        L.retarget(animate)\n        this.cal.set(\"cols\", L.colBoxes())\n        },\n\n    // a day key's grid position (col/row) in the displayed month, or -1/-1\n    cellPos(key) {\n        for (const rec of this.cal.value.days) {\n            if (rec.key == key) return { col: rec.col, row: rec.row }\n            }\n        return { col: -1, row: -1 }\n        },\n\n    // A cell is \"open\" (hour timeline, not the list) iff it is THE open day —\n    // set when a month cell opens in place, when `+` opens a week column, or on\n    // entering day view. Other week/month cells stay closed lists (SPEC §3).\n    isOpen(key) {\n        return key != \"\" && key == this.openKey\n        },\n\n    // Click an event → select its day AND the event; does NOT open the day\n    // (SPEC §6). The DayCell/event `selected` bindings react to the two keys.\n    selectEvent(id, key) {\n        this.selectedKey = key\n        this.selectedEvent = id\n        if (this.panelOpen) this.syncPanelFields()   // retarget the open panel (§5)\n        },\n\n    // ── event drag (SPEC §6) ──\n    // A press arms nothing; the first move makes it a drag (so a plain click\n    // never moves the bar). The day cell under the pointer hilites; dropping on\n    // a day moves the event there (same time), selecting that day. A drag\n    // swallows the click that the router pairs with the release.\n    catFill(cat) {\n        return cat == \"holiday\" ? 0xCBD1C5 : cat == \"astro\" ? 0xC5C3D5\n             : cat == \"milestone\" ? 0xBBC6D1 : 0xC6CEDC\n        },\n    startDrag(id) {\n        this.dragId = id\n        this.dragArmed = false\n        this.dragOccurred = false\n        const e = this.srcEvent(id)          // dress the ghost that follows the pointer\n        if (e != null) {\n            this.dragGhost.label.text = e.title\n            this.dragGhost.fill = this.catFill(e.category)\n            }\n        },\n    dragMove(rx, ry) {\n        if (this.dragId < 0) return\n        this.dragArmed = true\n        this.dragX = rx\n        this.dragY = ry\n        this.dragOverKey = this.dayAtPoint(rx, ry)\n        },\n    endDrag() {\n        if (this.dragId < 0) return\n        if (this.dragArmed) {\n            this.dragOccurred = true\n            const key = this.dayAtPoint(this.dragX, this.dragY)\n            if (key != \"\") this.dropEvent(this.dragId, key)\n            }\n        this.dragId = -1\n        this.dragArmed = false\n        this.dragOverKey = \"\"\n        },\n    dropEvent(id, key) {\n        const e = this.srcEvent(id)\n        if (e == null) return\n        const d = this.parseKey(key)\n        const dur = e.end - e.start\n        e.y = d.getFullYear(); e.m = d.getMonth() + 1; e.d = d.getDate()\n        // Dropping on an OPEN day sets the time from the drop-y (15-min snap,\n        // duration preserved, end ≤ 23:45 — SPEC §6 time-drag).\n        if (this.isOpen(key)) {\n            const t = this.timeAtPoint(key, this.dragY)\n            if (t >= 0) { e.start = Math.max(0, Math.min(t, 1425)); e.end = e.start + dur }\n            }\n        this.setMonth(this.year, this.month, key)     // selects the target day\n        this.selectedEvent = id\n        },\n\n    // The 15-min-snapped minute-of-day at an app-relative y inside an open day's\n    // timeline (accounts for the cell box and its scroll), or -1.\n    timeAtPoint(key, ry) {\n        for (const c of this.grid.children) {\n            if (c.dayKey == key && c.body != null && c.body.tl != null) {\n                const contentY = (ry - 57 - c.y - 19) - c.body.tl.y\n                return Math.round(((contentY - 11) / 22 * 60) / 15) * 15\n                }\n            }\n        return -1\n        },\n\n    // The day key whose (live) cell box contains an app-relative point, or \"\".\n    dayAtPoint(rx, ry) {\n        const gx = rx - 20, gy = ry - 57              // grid sits at (20, 57)\n        for (const c of this.grid.children) {\n            if (c.dayKey != null && c.visible\n                && gx >= c.x && gx < c.x + c.width\n                && gy >= c.y && gy < c.y + c.height) return c.dayKey\n            }\n        return \"\"\n        },\n\n    // The ⓘ button / double-click opens the info panel on an event (SPEC §7).\n    showInfo(id) {\n        this.selectedEvent = id\n        this.newEvent = false\n        this.openPanel()\n        },\n\n    // Open: grid contracts (snap −208), panel slides x852→622 + fades (500ms).\n    openPanel() {\n        this.panelOpen = true\n        this.grid.width = 600\n        this.relayout(false)\n        this.infoPanel.slideIn.start()\n        this.syncPanelFields()\n        },\n\n    // Close. A panel opened by Add Event on an unapplied new event deletes it on\n    // cancel (SPEC §7 cancel semantics); the grid re-expands (snap).\n    closePanel() {\n        if (this.newEvent && !this.applied) this.deleteEvent()\n        this.panelOpen = false\n        this.newEvent = false\n        this.grid.width = 808\n        this.relayout(false)\n        this.infoPanel.slideOut.start()\n        },\n\n    // The selected event's DISPLAY record (reactive over the store), or null.\n    selRec() {\n        if (this.selectedEvent < 0) return null\n        for (const day of this.cal.value.days)\n            for (const e of day.events)\n                if (e.id == this.selectedEvent) return e\n        return null\n        },\n\n    // The selected event's SOURCE record (what edits mutate; the display copies\n    // are re-derived by setMonth). Edits are in-memory only (SPEC §9).\n    srcEvent(id) {\n        return this.data.value.events.find(e => e.id == id)\n        },\n\n    longDate(rec) {\n        return rec != null ? this.monthName(rec.m) + \" \" + rec.d + \", \" + rec.y : \"\"\n        },\n\n    longTime(min) {\n        const h = Math.floor(min / 60), m = min % 60\n        return (h == 0 ? 12 : h > 12 ? h - 12 : h) + \":\"\n             + (m < 10 ? \"0\" + m : \"\" + m) + (h > 11 ? \"p\" : \"a\")\n        },\n\n    setTab(i) { this.openTab = i },\n\n    // Add Event (SPEC §8): a 9–10a \"New Event\" on the selected day, selected and\n    // opened in the panel. Closing without Apply deletes it (cancel semantics).\n    addEvent() {\n        const es = this.data.value.events\n        const id = 1 + es.reduce((mx, e) => Math.max(mx, e.id), 0)\n        const d = this.parseKey(this.selectedKey)\n        es.push({ id: id, y: d.getFullYear(), m: d.getMonth() + 1, d: d.getDate(),\n                  start: 540, end: 600, title: \"New Event\",\n                  notes: \"\", location: \"\", attendees: \"\", category: \"\" })\n        this.setMonth(this.year, this.month, this.selectedKey)\n        this.selectedEvent = id\n        this.newEvent = true\n        this.applied = false\n        this.openPanel()\n        },\n\n    // Push the selected event's text into the (editable, unbound) panel fields —\n    // on open and on retarget. Date/times stay bound to the record (spinners).\n    syncPanelFields() {\n        const e = this.selRec()\n        if (e == null) return\n        this.infoPanel.titleF.text = e.title\n        this.infoPanel.notesSec.area.text = e.notes != null ? e.notes : \"\"\n        this.infoPanel.locSec.area.text = e.location != null ? e.location : \"\"\n        this.infoPanel.attSec.area.text = e.attendees != null ? e.attendees : \"\"\n        },\n\n    // Apply commits the four text fields from the panel (SPEC §7).\n    apply() {\n        this.applyText(this.infoPanel.titleF.text, this.infoPanel.notesSec.area.text,\n                       this.infoPanel.locSec.area.text, this.infoPanel.attSec.area.text)\n        },\n\n    // Commit the text fields (title/notes/location/attendees) — Apply (SPEC §7).\n    applyText(title, notes, location, attendees) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        e.title = title; e.notes = notes; e.location = location; e.attendees = attendees\n        this.applied = true\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // Date ‹›: move the event ±1 day (crosses months by navigating — SPEC §7).\n    moveDay(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        const d = new Date(e.y, e.m - 1, e.d + delta)\n        e.y = d.getFullYear(); e.m = d.getMonth() + 1; e.d = d.getDate()\n        this.setMonth(e.y, e.m, this.keyOf(d))\n        },\n\n    // Start ‹›: ±15m MOVES the event (duration preserved), end clamped ≤ 23:45.\n    moveStart(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        const dur = e.end - e.start\n        e.start = Math.max(0, Math.min(e.start + delta, 1425))\n        e.end = e.start + dur\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // Dispatch a Stepper's nudge to the right edit (SPEC §7).\n    stepField(field, dir) {\n        if (field == \"date\") this.moveDay(dir)\n        else if (field == \"start\") this.moveStart(dir * 15)\n        else this.moveEnd(dir * 15)\n        },\n\n    // End ‹›: ±15m CHANGES duration (min 15m, max < 24h — SPEC §7).\n    moveEnd(delta) {\n        const e = this.srcEvent(this.selectedEvent)\n        if (e == null) return\n        e.end = Math.max(e.start + 15, Math.min(e.end + delta, 1439))\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    deleteEvent() {\n        const es = this.data.value.events\n        const i = es.findIndex(e => e.id == this.selectedEvent)\n        if (i >= 0) es.splice(i, 1)\n        this.selectedEvent = -1\n        this.setMonth(this.year, this.month, this.selectedKey)\n        },\n\n    // The 24 hour-gutter markers for the open timeline (SPEC §3): number, am/pm,\n    // the y of its hour rule (22px/hour, +11px half-hour zero), bold on 12a/12p.\n    buildHours() {\n        const hours = []\n        for (let h = 0; h < 24; h++)\n            hours.push({ num: \"\" + (h % 12 == 0 ? 12 : h % 12),\n                         ampm: h < 12 ? \"a\" : \"p\", y: h * 22 + 11, bold: h % 12 == 0 })\n        return hours\n        },\n\n    // Side-by-side lanes for overlapping open-timeline events (SPEC §12-E, fix).\n    // `events` is start-sorted; each disjoint cluster shares its own lane count\n    // so non-overlapping events stay full width (lane 0 of 1).\n    assignLanes(events) {\n        const flush = (cluster) => {\n            const laneEnd = []\n            for (const e of cluster) {\n                let ln = 0\n                while (ln < laneEnd.length && laneEnd[ln] > e.start) ln++\n                laneEnd[ln] = e.end\n                e.lane = ln\n                }\n            for (const e of cluster) e.lanes = laneEnd.length\n            }\n        let cluster = [], clusterEnd = 0\n        for (const e of events) {\n            if (cluster.length > 0 && e.start >= clusterEnd) { flush(cluster); cluster = []; clusterEnd = 0 }\n            cluster.push(e)\n            clusterEnd = Math.max(clusterEnd, e.end)\n            }\n        if (cluster.length > 0) flush(cluster)\n        },\n\n    // Startup (SPEC §10): once data is in, the top panel slides down and the\n    // grid fades up (the loading-still → panel → grid reveal).\n    onInit() {\n        App.data.fetch().then(() => {\n            const now = new Date()\n            App.setMonth(now.getFullYear(), now.getMonth() + 1)\n            App.top.slideDown.start()\n            App.grid.fadeIn.start()\n            })\n        },\n\n    // ── top panel (SPEC §1) ──\n\n    top: View [ x = 20, width = 806, y = -50,\n        slideDown: Animator [ attribute = y, to = 0, duration = 500, motion = laszloBoth ],\n\n        // the daynames bar sits behind the menubar strip (original stacking)\n        weekbar: View [ y = 26, width = 808, height = 26, fill = #354D5B,\n            datapath = { App.cal.value },\n            rule: View [ y = 25, width = { parent.width }, height = 1, fill = #708A94 ],\n\n            names: View [ y = 11, width = { parent.width }, height = 12,\n                DayName [ datapath = :cols[], x = :x, width = :w, height = 12, visible = :vis ],\n                ],\n            ],\n\n        mbar: View [ width = 806, height = 32,\n            strip: Image [ source = \"resources/mainbar-overlay.png\" ],\n            logo:  Image [ source = \"resources/logo.png\" ],\n\n            viewBtns: View [ x = 142, y = 4, width = 174, height = 17, cornerRadius = 8,\n                fill = gradient(stop(0, 0xD9DFDF), stop(0.35, 0xB4BDBF), stop(1, 0x5C717D)),\n                stroke = stroke(1, #143B45),\n\n                // segment separators + the three tiny icons, drawn\n                draw(d) {\n                    d.fillStyle = 0x143B45\n                    d.fillRect(47, 0, 1, height)\n                    d.fillRect(104, 0, 1, height)\n                    // day: a page outline\n                    d.fillRect(8, 5, 8, 1); d.fillRect(8, 12, 8, 1)\n                    d.fillRect(8, 5, 1, 8); d.fillRect(15, 5, 1, 8)\n                    // week: four bars\n                    d.fillRect(55, 5, 2, 8); d.fillRect(58, 5, 2, 8)\n                    d.fillRect(61, 5, 2, 8); d.fillRect(64, 5, 2, 8)\n                    // month: a 3×3 dot grid\n                    d.fillRect(112, 5, 2, 2); d.fillRect(115, 5, 2, 2); d.fillRect(118, 5, 2, 2)\n                    d.fillRect(112, 8, 2, 2); d.fillRect(115, 8, 2, 2); d.fillRect(118, 8, 2, 2)\n                    d.fillRect(112, 11, 2, 2); d.fillRect(115, 11, 2, 2); d.fillRect(118, 11, 2, 2)\n                    },\n\n                dayLbl:   Text [ x = 20,  y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"day\" ],\n                weekLbl:  Text [ x = 69,  y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"week\" ],\n                monthLbl: Text [ x = 124, y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                    textShadow = shadow(0, -1, 0, #33555577), text = \"month\" ],\n\n                dayHit:   View [ x = 0,   width = 47, height = 17, onClick() { App.showDay() } ],\n                weekHit:  View [ x = 47,  width = 57, height = 17, onClick() { App.showWeek() } ],\n                monthHit: View [ x = 104, width = 70, height = 17, onClick() { App.showMonth() } ],\n                ],\n\n            monthCtl: View [ x = 321, y = 8, width = 161, height = 17, cornerRadius = 8,\n                fill = gradient(stop(0, 0xBBC3C5), stop(0.4, 0xC5CCCF), stop(1, 0x7A8B94)),\n                stroke = stroke(1, #24424F),\n\n                // the segment separators: incised VERTICAL grooves (dark line\n                // + a highlight one px to its right), dividing the arrow caps\n                // from the title — oracle-measured at x16 / x142.\n                draw(d) {\n                    d.fillStyle = 0x143B45\n                    d.fillRect(16, 0, 1, 17)\n                    d.fillRect(142, 0, 1, 17)\n                    d.fillStyle = 0xD9DFDF\n                    d.fillRect(17, 0, 1, 17)\n                    d.fillRect(143, 0, 1, 17)\n                    // the cap arrows\n                    d.fillStyle = 0xFFFFFF\n                    d.beginPath()\n                    d.moveTo(14, 4); d.lineTo(7, 8.5); d.lineTo(14, 13)\n                    d.fill()\n                    d.beginPath()\n                    d.moveTo(147, 4); d.lineTo(154, 8.5); d.lineTo(147, 13)\n                    d.fill()\n                    },\n\n                prevBtn: View [ width = 24, height = 17, onClick() { App.step(-1) } ],\n                nextBtn: View [ x = 137, width = 24, height = 17, onClick() { App.step(1) } ],\n                ],\n\n            // bold white centered title with the drop shadow the original\n            // faked with a second offset text view — here one textShadow.\n            monthTitle: Text [ y = 10, fontWeight = bold, textColor = #FFFFFF,\n                x = { (parent.width - this.width) / 2 - 2 },\n                textShadow = shadow(0, -1, 0, #143B4580),\n                text = { App.month > 0 ? App.monthName(App.month) + \" \" + App.year : \"\" } ],\n\n            addBtn: CalButton [ x = 496, y = 5, width = 76, label = \"Add Event\",\n                onClick() { App.addEvent() } ],\n            ],\n        ],\n\n    // ── the grid (SPEC §2) ──\n\n    grid: View [ x = 20, y = 57, width = 808, height = 516, opacity = 0,\n        fadeIn: Animator [ attribute = opacity, to = 1, duration = 1000, motion = laszloBoth ],\n        datapath = { App.cal.value },\n        layout: CalendarGrid [ ],\n\n        DayCell [ datapath = :days[], dayKey = :key,\n            selected = { App.selectedKey == this.dayKey },\n            open = { App.isOpen(this.dayKey) },\n            onClick() { App.openDay(this.dayKey) } ],\n        ],\n\n    // ── the info panel (SPEC §7) — slides in from the right over the grid ────\n    // Beveled body drawn in neo (the original was 9-slice bitmaps); bound to the\n    // selected event's record; date/time ‹› nudges edit it live.\n\n    infoPanel: View [ x = 852, y = 57, width = 205, height = 516, opacity = 0,\n        visible = { opacity > 0 },\n        datapath = { App.selRec() },\n        fill = #C6CAC4,\n        stroke = stroke(1, #83877F),\n\n        slideIn:  AnimatorGroup [ process = simultaneous, duration = 500, motion = laszloBoth,\n            Animator [ attribute = x, to = 622 ],\n            Animator [ attribute = opacity, to = 1 ] ],\n        slideOut: AnimatorGroup [ process = simultaneous, duration = 500, motion = laszloBoth,\n            Animator [ attribute = x, to = 852 ],\n            Animator [ attribute = opacity, to = 0 ] ],\n\n        bar: View [ width = { parent.width }, height = 18, fill = #384852,\n            cap: Text [ x = 8, y = 3, fontSize = 10, fontWeight = bold, textColor = #FFFFFF,\n                        text = \"Event Info\" ],\n            xbtn: View [ x = { parent.width - 15 }, y = 4, width = 11, height = 11,\n                draw(d) {\n                    d.fillStyle = 0xFFFFFF\n                    d.lineWidth = 1.5\n                    d.beginPath(); d.moveTo(2, 2); d.lineTo(9, 9)\n                    d.moveTo(9, 2); d.lineTo(2, 9); d.stroke()\n                    },\n                onClick() { app.closePanel() } ],\n            ],\n\n        titleF: TextInput [ x = 6, y = 24, width = 193, height = 17, fill = #FFFFFF,\n            fontSize = 11, textColor = #333333 ],\n\n        dateStep:  Stepper [ x = 8, y = 47, width = 189, field = \"date\",\n            label = { app.monthName(:m) + \" \" + :d + \", \" + :y } ],\n        startStep: Stepper [ x = 8, y = 66, width = 82, field = \"start\",\n            label = { app.longTime(:start) } ],\n        toLbl:     Text [ x = 94, y = 68, fontSize = 10, textColor = #2E3E48, text = \"to\" ],\n        endStep:   Stepper [ x = 115, y = 66, width = 82, field = \"end\",\n            label = { app.longTime(:end) } ],\n\n        notesSec: AccordionSection [ x = 4, idx = 0, label = \"Notes\" ],\n        locSec:   AccordionSection [ x = 4, idx = 1, label = \"Location\" ],\n        attSec:   AccordionSection [ x = 4, idx = 2, label = \"Attendees\" ],\n\n        applyBtn:  CalButton [ x = 8, y = 486, width = 82, label = \"Apply\",\n            onClick() { app.apply() } ],\n        deleteBtn: CalButton [ x = 115, y = 486, width = 82, label = \"Delete\",\n            onClick() { app.deleteEvent(); app.closePanel() } ],\n        ],\n\n    // A ghost of the dragged event that follows the pointer (SPEC §6) — the top\n    // layer, shown once a press turns into a drag. Its label/fill are dressed in\n    // startDrag; x/y track the app-relative pointer.\n    dragGhost: View [ visible = { App.dragId >= 0 && App.dragArmed },\n        x = { App.dragX - 10 }, y = { App.dragY - 9 },\n        width = 132, height = 18, opacity = 0.82, cornerRadius = 3,\n        fill = #C6CEDC, stroke = stroke(1, #8A98A4),\n        label: Text [ x = 7, y = 3, fontSize = 10, textColor = #3A4650, text = \"\" ],\n        ],\n    ]\n"},"precompiled":{},"library":{"manifest":{"Bar":"bar.declare"},"files":{"library/src/bar.declare":"// Bar — a horizontal value bar: an optional label, then a rounded track that\n// fills to `value` (0–100). A PLACEHOLDER component (see composition.md §1a):\n// coherent and restyleable — override `tint` for the fill — but not the final\n// widget; the real component library is a later, dedicated effort.\nclass Bar extends View [ height = 28,\n    label: string = \"\",\n    value: number = 0,\n    tint:  Color  = #4C8DFF,\n    lead:  number = { label == \"\" ? 0 : 96 },\n    cap: Text [ y = 5, fontSize = 14, textColor = #8A9BA6, text = { classroot.label } ],\n    rail: View [ x = { classroot.lead }, width = { parent.width - classroot.lead },\n                 height = { parent.height }, cornerRadius = 6, fill = #0A1119,\n        bar: View [ height = { parent.height }, cornerRadius = 6, fill = { classroot.tint },\n                    width = { parent.width * classroot.value / 100 } ] ],\n    ]\n"}},"closure":{"props":{"backend":"dom"},"entries":[{"id":"examples/neocalendar/neocalendar.declare","kind":"file","v":{"hash":"1e2d5e7e36bee43c"}},{"id":"library/autoincludes.json","kind":"file","v":{"hash":"14270b41cb061f29"}}]},"mainId":"examples/neocalendar/neocalendar.declare"};
